<section class="eco-card"><h1>Logs</h1><?php if (!empty($errorMessage)): ?><div class="eco-alert"><?= e((string)$errorMessage) ?></div><?php endif; ?><table class="eco-table"><thead><tr><th>ID</th><th>Tenant</th><th>User</th><th>Level</th><th>Channel</th><th>Message</th><th>Context</th><th>Fecha</th></tr></thead><tbody><?php foreach (($logs ?? []) as $row): ?><tr><td><?= e((string)$row['id']) ?></td><td><?= e((string)($row['tenant_id'] ?? '-')) ?></td><td><?= e((string)($row['user_id'] ?? '-')) ?></td><td><span class="eco-badge"><?= e((string)$row['level']) ?></span></td><td><?= e((string)$row['channel']) ?></td><td><?= e((string)$row['message']) ?></td><td><?= e(strlen((string)($row['context'] ?? '')) > 80 ? substr((string)$row['context'],0,80).'…' : (string)($row['context'] ?? '')) ?></td><td><?= e((string)$row['created_at']) ?></td></tr><?php endforeach; ?></tbody></table></section>
